+  background: var(--ink-2);
+  font-size: 10.5px;
+  letter-spacing: 0.04em;
+  color: var(--fg-faint);
+  gap: 18px;
+  text-transform: uppercase;
+}
+
+.sidebar {
+  border-right: 1px solid var(--rule);
+  background: var(--ink);
+  display: flex;
+  flex-direction: column;
+  overflow: hidden;
+}
+
+.main {
+  overflow: auto;
+  background: var(--ink);
+  position: relative;
+}
+
+/* Topbar */
+.brand {
+  display: flex;
+  align-items: center;
+  gap: 8px;
+  padding: 0 14px;
+  border-right: 1px solid var(--rule);
+  height: 100%;
+  width: 220px;
+}
+.brand-mark {
+  width: 14px;
+  height: 14px;
+  position: relative;
+}
+.brand-mark::before, .brand-mark::after {
+  content: '';
+  position: absolute;
+  background: var(--verifier-bright);
+}
+.brand-mark::before { left: 0; top: 0; width: 14px; height: 2px; }
+.brand-mark::after  { left: 6px; top: 0; width: 2px; height: 14px; }
+.brand-name {
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 12px;
+  letter-spacing: 0.18em;
+  color: var(--fg);
+  text-transform: uppercase;
+}
+.brand-name .dim { color: var(--fg-faint); }
+
+.topbar-tabs {
+  display: flex;
+  height: 100%;
+}
+.topbar-tab {
+  padding: 0 16px;
+  display: flex;
+  align-items: center;
+  font-size: 11px;
+  letter-spacing: 0.08em;
+  text-transform: uppercase;
+  color: var(--fg-dim);
+  cursor: pointer;
+  border-right: 1px solid var(--rule);
+  font-family: 'JetBrains Mono', monospace;
+}
+.topbar-tab:hover { color: var(--fg); background: var(--ink-2); }
+.topbar-tab.active { color: var(--verifier-bright); }
+.topbar-tab.active::before {
+  content: '●';
+  margin-right: 6px;
+  font-size: 8px;
+  color: var(--verifier-bright);
+}
+
+.topbar-spacer { flex: 1; }
+
+.endpoint-pill {
+  display: flex;
+  align-items: center;
+  gap: 8px;
+  padding: 0 12px;
+  height: 100%;
+  border-left: 1px solid var(--rule);
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 11px;
+  color: var(--fg-dim);
+  cursor: pointer;
+}
+.endpoint-pill:hover { background: var(--ink-2); }
+.endpoint-pill .conn-dot {
+  width: 6px; height: 6px; border-radius: 50%;
+  background: var(--verifier-bright);
+  box-shadow: 0 0 6px var(--verifier-bright);
+}
+
+/* Sidebar */
+.side-section {
+  padding: 12px 14px 6px;
+  font-size: 9.5px;
+  letter-spacing: 0.16em;
+  text-transform: uppercase;
+  color: var(--fg-faint);
+  font-family: 'JetBrains Mono', monospace;
+}
+
+.nav-item {
+  display: flex;
+  align-items: center;
+  gap: 10px;
+  padding: 6px 14px;
+  font-size: 12px;
+  color: var(--fg-dim);
+  cursor: pointer;
+  border-left: 2px solid transparent;
+  font-family: 'JetBrains Mono', monospace;
+  letter-spacing: 0.02em;
+}
+.nav-item:hover { background: var(--ink-2); color: var(--fg); }
+.nav-item.active {
+  color: var(--fg);
+  background: var(--ink-2);
+  border-left-color: var(--verifier-bright);
+}
+.nav-item .badge {
+  margin-left: auto;
+  font-size: 10px;
+  color: var(--fg-faint);
+  background: var(--ink-3);
+  padding: 1px 6px;
+  border-radius: 2px;
+}
+.nav-item.active .badge { color: var(--verifier-bright); }
+
+.nav-glyph {
+  width: 12px;
+  display: inline-flex;
+  justify-content: center;
+  color: var(--fg-faint);
+  font-size: 11px;
+}
+.nav-item.active .nav-glyph { color: var(--verifier-bright); }
+
+/* Witness HUD — bottom of sidebar */
+.witness-hud {
+  margin-top: auto;
+  border-top: 1px solid var(--rule);
+  padding: 10px 14px;
+  background: var(--ink-2);
+  font-family: 'JetBrains Mono', monospace;
+}
+.witness-hud-label {
+  font-size: 9px;
+  letter-spacing: 0.18em;
+  text-transform: uppercase;
+  color: var(--fg-faint);
+  margin-bottom: 4px;
+  display: flex;
+  justify-content: space-between;
+}
+.witness-hud-hex {
+  font-size: 11px;
+  color: var(--verifier-bright);
+  letter-spacing: 0.02em;
+  word-break: break-all;
+}
+.witness-hud-meta {
+  margin-top: 6px;
+  display: flex;
+  gap: 10px;
+  font-size: 10px;
+  color: var(--fg-faint);
+}
+
+/* Main scroll panes */
+.pane-header {
+  height: 32px;
+  border-bottom: 1px solid var(--rule);
+  display: flex;
+  align-items: center;
+  padding: 0 14px;
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 11px;
+  letter-spacing: 0.1em;
+  text-transform: uppercase;
+  color: var(--fg-dim);
+  background: var(--ink);
+  position: sticky;
+  top: 0;
+  z-index: 5;
+  gap: 12px;
+}
+.pane-header .crumb-sep { color: var(--fg-faint); }
+.pane-header .crumb-active { color: var(--fg); }
+.pane-header .header-actions {
+  margin-left: auto;
+  display: flex;
+  gap: 6px;
+}
+
+/* Buttons */
+.btn {
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 11px;
+  letter-spacing: 0.06em;
+  text-transform: uppercase;
+  background: transparent;
+  color: var(--fg-dim);
+  border: 1px solid var(--rule);
+  padding: 5px 10px;
+  cursor: pointer;
+  transition: background 80ms, color 80ms, border-color 80ms;
+}
+.btn:hover { color: var(--fg); border-color: var(--fg-dim); background: var(--ink-2); }
+.btn-primary {
+  border-color: var(--verifier);
+  color: var(--verifier-bright);
+}
+.btn-primary:hover {
+  background: rgba(45,140,93,0.08);
+  border-color: var(--verifier-bright);
+  color: var(--verifier-bright);
+}
+.btn-amber {
+  border-color: #5a401e;
+  color: var(--refused-bright);
+}
+.btn-amber:hover { background: rgba(232,149,72,0.06); border-color: var(--refused); }
+
+/* Tables */
+.tbl {
+  width: 100%;
+  border-collapse: collapse;
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 12px;
+}
+.tbl th {
+  text-align: left;
+  font-weight: 400;
+  font-size: 10px;
+  letter-spacing: 0.12em;
+  text-transform: uppercase;
+  color: var(--fg-faint);
+  padding: 8px 12px;
+  border-bottom: 1px solid var(--rule);
+  background: var(--ink-2);
+  position: sticky;
+  top: 0;
+}
+.tbl td {
+  padding: 7px 12px;
+  border-bottom: 1px solid var(--rule);
+  color: var(--fg);
+  vertical-align: middle;
+}
+.tbl tr:hover td { background: var(--ink-2); }
+.tbl tr.selected td { background: rgba(45,140,93,0.06); }
+.tbl .num { text-align: right; font-variant-numeric: tabular-nums; }
+.tbl .dim { color: var(--fg-faint); }
+
+/* Stat tiles row */
+.tile-row {
+  display: grid;
+  grid-template-columns: repeat(6, 1fr);
+  border-bottom: 1px solid var(--rule);
+}
+.tile {
+  padding: 14px 16px;
+  border-right: 1px solid var(--rule);
+  font-family: 'JetBrains Mono', monospace;
+}
+.tile:last-child { border-right: none; }
+.tile-label {
+  font-size: 9.5px;
+  letter-spacing: 0.18em;
+  text-transform: uppercase;
+  color: var(--fg-faint);
+  margin-bottom: 6px;
+}
+.tile-value {
+  font-size: 22px;
+  color: var(--fg);
+  font-weight: 500;
+  letter-spacing: -0.01em;
+  font-variant-numeric: tabular-nums;
+}
+.tile-value .unit { font-size: 11px; color: var(--fg-faint); margin-left: 4px; }
+.tile-delta {
+  font-size: 10px;
+  color: var(--verifier-bright);
+  margin-top: 2px;
+}
+.tile-delta.down { color: var(--refused-bright); }
+
+/* Sparkline */
+.spark {
+  display: block;
+  width: 100%;
+  height: 28px;
+  margin-top: 6px;
+}
+
+/* Verifier-green / amber states */
+.tag {
+  display: inline-flex;
+  align-items: center;
+  gap: 4px;
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 9.5px;
+  letter-spacing: 0.14em;
+  text-transform: uppercase;
+  padding: 2px 6px;
+  border: 1px solid currentColor;
+  line-height: 1;
+}
+.tag-verified { color: var(--verifier-bright); }
+.tag-refused  { color: var(--refused-bright); }
+.tag-degraded { color: var(--refused-bright); border-style: dashed; }
+.tag-cold     { color: var(--fg-faint); }
+.tag-warm     { color: var(--accent-cyan); }
+
+.dot {
+  display: inline-block;
+  width: 6px; height: 6px;
+  border-radius: 50%;
+  margin-right: 6px;
+  vertical-align: middle;
+}
+.dot-verified { background: var(--verifier-bright); box-shadow: 0 0 5px var(--verifier-bright); }
+.dot-refused  { background: var(--refused-bright); }
+.dot-cold     { background: var(--fg-faint); }
+.dot-warm     { background: var(--accent-cyan); }
+
+/* Receipt panel — paper cream */
+.receipt {
+  background: var(--paper);
+  color: var(--paper-ink);
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 11.5px;
+  line-height: 1.55;
+  padding: 18px 20px 22px;
+  position: relative;
+  box-shadow:
+    0 1px 0 var(--paper-rule),
+    0 -1px 0 var(--paper-rule);
+}
+.receipt::before, .receipt::after {
+  content: '';
+  position: absolute;
+  left: 0; right: 0;
+  height: 8px;
+  background-image: radial-gradient(circle at 4px 0, var(--ink) 3px, transparent 3.2px);
+  background-size: 8px 8px;
+  background-repeat: repeat-x;
+}
+.receipt::before { top: -4px; background-position: 0 -4px; }
+.receipt::after { bottom: -4px; background-position: 0 4px; }
+
+.receipt-head {
+  display: flex;
+  justify-content: space-between;
+  align-items: flex-start;
+  border-bottom: 1px dashed var(--paper-rule);
+  padding-bottom: 10px;
+  margin-bottom: 10px;
+}
+.receipt-title {
+  font-size: 13px;
+  letter-spacing: 0.18em;
+  text-transform: uppercase;
+}
+.receipt-sub {
+  font-size: 10px;
+  color: var(--paper-dim);
+  letter-spacing: 0.08em;
+  margin-top: 2px;
+}
+.receipt-row {
+  display: flex;
+  justify-content: space-between;
+  padding: 2px 0;
+}
+.receipt-row .k { color: var(--paper-dim); letter-spacing: 0.04em; }
+.receipt-row .v { font-variant-numeric: tabular-nums; }
+.receipt-divider {
+  border-bottom: 1px dashed var(--paper-rule);
+  margin: 8px 0;
+}
+.receipt-stamp {
+  margin-top: 14px;
+  padding: 10px 12px;
+  border: 2px solid var(--verifier);
+  color: var(--verifier);
+  text-align: center;
+  letter-spacing: 0.3em;
+  font-size: 14px;
+  font-weight: 600;
+  position: relative;
+  transform: rotate(-1.2deg);
+}
+.receipt-stamp.refused {
+  border-color: var(--refused);
+  color: var(--refused);
+}
+.receipt-foot {
+  margin-top: 12px;
+  padding-top: 10px;
+  border-top: 1px dashed var(--paper-rule);
+  font-size: 10px;
+  color: var(--paper-dim);
+  word-break: break-all;
+  letter-spacing: 0.04em;
+}
+
+/* Witness hex — eliding */
+.hex {
+  font-family: 'JetBrains Mono', monospace;
+  letter-spacing: 0.02em;
+  cursor: help;
+}
+.hex .full { display: none; }
+.hex:hover .elided { display: none; }
+.hex:hover .full { display: inline; }
+
+/* Code/JSON block */
+.codeblock {
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 11.5px;
+  line-height: 1.5;
+  background: var(--ink-2);
+  border: 1px solid var(--rule);
+  padding: 10px 12px;
+  white-space: pre;
+  overflow: auto;
+  color: var(--fg);
+}
+.codeblock .k { color: var(--accent-cyan); }
+.codeblock .s { color: var(--verifier-bright); }
+.codeblock .n { color: var(--refused-bright); }
+.codeblock .c { color: var(--fg-faint); }
+
+/* Two-column split */
+.split {
+  display: grid;
+  grid-template-columns: 1fr 380px;
+  height: 100%;
+}
+.split > * { min-width: 0; }
+.split .right {
+  border-left: 1px solid var(--rule);
+  background: var(--ink-2);
+  overflow: auto;
+}
+
+/* Form controls */
+.field-row { display: flex; flex-direction: column; gap: 4px; padding: 10px 14px; border-bottom: 1px solid var(--rule); }
+.field-label {
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 9.5px;
+  letter-spacing: 0.16em;
+  text-transform: uppercase;
+  color: var(--fg-faint);
+}
+.input, .textarea, .select {
+  background: var(--ink);
+  color: var(--fg);
+  border: 1px solid var(--rule);
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 12px;
+  padding: 6px 8px;
+  outline: none;
+  width: 100%;
+}
+.input:focus, .textarea:focus, .select:focus { border-color: var(--verifier); }
+.textarea { min-height: 80px; resize: vertical; }
+
+/* Segmented */
+.seg {
+  display: inline-flex;
+  border: 1px solid var(--rule);
+}
+.seg-item {
+  padding: 5px 10px;
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 10.5px;
+  letter-spacing: 0.1em;
+  text-transform: uppercase;
+  color: var(--fg-faint);
+  cursor: pointer;
+  border-right: 1px solid var(--rule);
+}
+.seg-item:last-child { border-right: none; }
+.seg-item:hover { color: var(--fg); background: var(--ink-2); }
+.seg-item.active { color: var(--verifier-bright); background: rgba(45,140,93,0.06); }
+
+/* Tape — for audit lines / decision trace */
+.tape {
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 11.5px;
+  border-top: 1px solid var(--rule);
+}
+.tape-row {
+  display: grid;
+  grid-template-columns: 90px 90px 60px 1fr auto;
+  gap: 12px;
+  padding: 5px 14px;
+  border-bottom: 1px solid var(--rule);
+  align-items: baseline;
+}
+.tape-row:hover { background: var(--ink-2); }
+.tape-row.refused { border-left: 2px solid var(--refused); padding-left: 12px; }
+.tape-row.ok      { border-left: 2px solid var(--verifier); padding-left: 12px; }
+.tape-row.degraded { border-left: 2px solid var(--refused); border-left-style: dashed; padding-left: 12px; }
+.tape-ts { color: var(--fg-faint); }
+.tape-prin { color: var(--accent-cyan); }
+.tape-tool { color: var(--fg); }
+.tape-msg { color: var(--fg-dim); overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
+.tape-code { font-size: 9.5px; color: var(--fg-faint); }
+
+/* ASCII sparkline */
+.ascii-spark {
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 10px;
+  letter-spacing: 0;
+  color: var(--verifier-bright);
+  white-space: pre;
+}
+
+/* Halt strip */
+.halt-strip {
+  height: 4px;
+  background:
+    repeating-linear-gradient(90deg,
+      var(--rule) 0 8px,
+      transparent 8px 16px);
+}
+
+/* Fingerprint reveal animation */
+@keyframes fingerprint-in {
+  0% { opacity: 0; filter: blur(8px); transform: scale(0.96); }
+  60% { opacity: 1; filter: blur(0); }
+  100% { opacity: 1; filter: blur(0); transform: scale(1); }
+}
+.fingerprint-reveal { animation: fingerprint-in 600ms ease-out; }
+
+/* Witness comparator */
+.witness-comparator {
+  display: grid;
+  grid-template-columns: 1fr;
+  gap: 10px;
+  padding: 14px 18px;
+  background: var(--ink-2);
+  border: 1px solid var(--rule);
+  font-family: 'JetBrains Mono', monospace;
+}
+.witness-line {
+  display: grid;
+  grid-template-columns: 80px 1fr;
+  gap: 14px;
+  align-items: center;
+  font-size: 11.5px;
+}
+.witness-line .label {
+  font-size: 9.5px;
+  letter-spacing: 0.16em;
+  text-transform: uppercase;
+  color: var(--fg-faint);
+}
+.witness-line .hex-full {
+  word-break: break-all;
+  color: var(--fg);
+}
+
+/* Key-value grid */
+.kv {
+  display: grid;
+  grid-template-columns: 160px 1fr;
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 11.5px;
+}
+.kv > div {
+  padding: 5px 14px;
+  border-bottom: 1px solid var(--rule);
+}
+.kv > .k {
+  color: var(--fg-faint);
+  font-size: 10px;
+  letter-spacing: 0.1em;
+  text-transform: uppercase;
+  background: var(--ink-2);
+  border-right: 1px solid var(--rule);
+}
+.kv > .v { color: var(--fg); word-break: break-all; }
+
+/* Bar (progress) */
+.bar {
+  height: 4px;
+  background: var(--ink-3);
+  position: relative;
+  overflow: hidden;
+}
+.bar-fill {
+  position: absolute;
+  left: 0; top: 0; bottom: 0;
+  background: var(--verifier-bright);
+}
+.bar-fill.amber { background: var(--refused-bright); }
+
+/* Histogram bars (latency) */
+.histo {
+  display: flex;
+  align-items: flex-end;
+  gap: 1px;
+  height: 56px;
+}
+.histo-bar {
+  flex: 1;
+  background: var(--verifier);
+  min-width: 2px;
+}
+.histo-bar.refused { background: var(--refused); }
+
+/* Refusals list */
+.refusal {
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 11.5px;
+  padding: 8px 12px;
+  border: 1px solid var(--refused);
+  border-left-width: 3px;
+  background: rgba(200,123,44,0.04);
+  margin-bottom: 6px;
+}
+.refusal .head {
+  display: flex;
+  justify-content: space-between;
+  margin-bottom: 4px;
+}
+.refusal .code {
+  color: var(--refused-bright);
+  letter-spacing: 0.1em;
+  font-size: 10px;
+}
+.refusal .target { color: var(--fg); }
+.refusal .reason { color: var(--fg-dim); font-size: 11px; }
+
+/* Tooltips, etc. */
+.kbd {
+  display: inline-block;
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 9.5px;
+  padding: 1px 5px;
+  border: 1px solid var(--rule);
+  color: var(--fg-faint);
+  margin-left: 4px;
+}
+
+/* Scrollbars */
+::-webkit-scrollbar { width: 8px; height: 8px; }
+::-webkit-scrollbar-track { background: var(--ink); }
+::-webkit-scrollbar-thumb { background: var(--ink-3); }
+::-webkit-scrollbar-thumb:hover { background: var(--ink-4); }
+
+/* Debug console */
+.debug-console {
+  position: fixed;
+  left: 0; right: 0; bottom: 28px;
+  height: 240px;
+  background: #07090d;
+  border-top: 1px solid var(--rule);
+  display: flex;
+  flex-direction: column;
+  z-index: 100;
+  font-family: 'JetBrains Mono', monospace;
+  box-shadow: 0 -8px 24px rgba(0,0,0,0.4);
+}
+.debug-console.collapsed { height: 30px; }
+.debug-head {
+  height: 30px;
+  border-bottom: 1px solid var(--rule);
+  display: flex;
+  align-items: center;
+  gap: 12px;
+  padding: 0 12px;
+  font-size: 10.5px;
+  color: var(--fg-faint);
+  flex-wrap: wrap;
+}
+.debug-title { color: var(--verifier-bright); letter-spacing: 0.1em; text-transform: uppercase; }
+.debug-count { font-size: 10px; }
+.debug-filter { margin-left: auto; display: flex; gap: 8px; }
+.debug-filter-item {
+  cursor: pointer; padding: 2px 6px; font-size: 10px;
+  letter-spacing: 0.08em; text-transform: uppercase;
+  color: var(--fg-faint); border: 1px solid transparent;
+}
+.debug-filter-item:hover { color: var(--fg); }
+.debug-filter-item.active { color: var(--verifier-bright); border-color: var(--verifier); }
+.debug-btn {
+  background: transparent;
+  border: 1px solid var(--rule);
+  color: var(--fg-faint);
+  font-family: inherit;
+  font-size: 10px;
+  padding: 2px 8px;
+  cursor: pointer;
+  letter-spacing: 0.06em;
+  text-transform: uppercase;
+}
+.debug-btn:hover { color: var(--fg); border-color: var(--fg-dim); }
+.debug-body {
+  flex: 1;
+  overflow-y: auto;
+  padding: 4px 0;
+  font-size: 11.5px;
+  line-height: 1.5;
+}
+.debug-line {
+  display: grid;
+  grid-template-columns: 90px 50px 1fr;
+  gap: 10px;
+  padding: 1px 12px;
+  border-left: 2px solid transparent;
+}
+.debug-line:hover { background: rgba(255,255,255,0.02); }
+.debug-line.debug-log { border-left-color: var(--verifier); }
+.debug-line.debug-info { border-left-color: var(--accent-cyan); }
+.debug-line.debug-warn { border-left-color: var(--refused); }
