+/* SVG element animations inside slides */
+.intro-anim-fade { animation: introFade 600ms ease-out both; }
+.intro-anim-shake { animation: introShake 800ms ease-out 400ms both; }
+.intro-anim-points circle { animation: introPointPop 400ms cubic-bezier(0.2,0.7,0.25,1) both; }
+.intro-anim-points g:nth-child(1) circle { animation-delay: 0ms; }
+.intro-anim-points g:nth-child(2) circle { animation-delay: 50ms; }
