+.intro-anim-pop { animation: introPop 500ms cubic-bezier(0.2,0.7,0.25,1) both; }
+.intro-anim-flow { animation: introFlow 600ms ease-out both; animation-delay: 300ms; }
+@keyframes introFade {
+  from { opacity: 0; }
+  to { opacity: 1; }
+}
+@keyframes introShake {
+  0% { opacity: 0; transform: translateX(0); }
+  20%, 100% { opacity: 1; }
+  30% { transform: translateX(-2px); }
+  50% { transform: translateX(2px); }
+  70% { transform: translateX(-1px); }
+  90% { transform: translateX(0); }
+}
+@keyframes introPointPop {
+  from { opacity: 0; transform: scale(0.4); transform-origin: center; transform-box: fill-box; }
+  to { opacity: 0.7; transform: scale(1); }
+}
+@keyframes introCardIn {
+  from { opacity: 0; transform: translateY(8px); }
+  to { opacity: 1; transform: translateY(0); }
+}
+@keyframes introPop {
+  from { opacity: 0; transform: scale(0.92); transform-origin: center; transform-box: fill-box; }
+  to { opacity: 1; transform: scale(1); }
+}
+@keyframes introFlow {
+  from { opacity: 0; }
+  to { opacity: 1; }
+}
+
+.intro-show-controls {
+  display: flex;
+  align-items: center;
+  gap: 12px;
+  padding: 0 4px;
+}
+.intro-show-dots {
+  display: flex;
+  gap: 6px;
+  flex: 1;
+  justify-content: center;
+}
+.intro-show-dot {
+  width: 24px;
+  height: 3px;
+  border: none;
+  background: var(--rule);
+  cursor: pointer;
+  padding: 0;
+  transition: background 200ms, width 200ms;
+}
+.intro-show-dot:hover { background: var(--fg-faint); }
+.intro-show-dot.active {
+  background: var(--verifier-bright);
+  box-shadow: 0 0 6px rgba(var(--verifier-rgb), 0.5);
+}
+.intro-show-pause {
+  background: transparent;
+  border: 1px solid var(--rule);
+  color: var(--fg-faint);
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 10px;
+  padding: 4px 9px;
+  cursor: pointer;
+  letter-spacing: 0.06em;
+  transition: border-color 120ms, color 120ms;
+}
+.intro-show-pause:hover {
+  border-color: var(--verifier-bright);
+  color: var(--verifier-bright);
+}
+
+/* Modals */
+.modal-backdrop {
+  position: fixed; inset: 0;
+  background: rgba(0,0,0,0.55);
+  backdrop-filter: blur(4px);
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  z-index: 200;
+  padding: 20px;
+}
+.modal {
+  background: var(--ink-1);
+  border: 1px solid var(--rule);
+  box-shadow: 0 20px 60px rgba(0,0,0,0.6), 0 0 0 1px rgba(45,140,93,0.1);
+  max-height: 80vh;
+  display: flex;
+  flex-direction: column;
+  font-family: 'Inter', sans-serif;
+}
+.modal-head {
+  display: flex;
+  align-items: flex-start;
+  justify-content: space-between;
+  padding: 16px 18px 12px;
+  border-bottom: 1px solid var(--rule);
+  gap: 12px;
+}
+.modal-title { font-size: 13px; font-weight: 600; color: var(--fg); letter-spacing: 0.02em; }
+.modal-sub { font-size: 11px; color: var(--fg-faint); margin-top: 3px; font-family: 'JetBrains Mono', monospace; }
+.modal-x {
+  background: transparent; border: 1px solid var(--rule);
+  color: var(--fg-faint); width: 24px; height: 24px;
+  font-size: 14px; cursor: pointer; line-height: 1;
+}
+.modal-x:hover { color: var(--fg); border-color: var(--fg-dim); }
+.modal-body { padding: 16px 18px; overflow-y: auto; flex: 1; }
+.modal-foot {
+  padding: 12px 18px;
+  border-top: 1px solid var(--rule);
+  display: flex;
+  justify-content: flex-end;
+  gap: 8px;
+}
+.store-row {
+  display: flex;
+  align-items: center;
+  gap: 12px;
+  padding: 10px 12px;
+  border: 1px solid var(--rule);
+  margin-bottom: 6px;
+  cursor: pointer;
+  transition: border-color 120ms;
+}
+.store-row:hover { border-color: var(--verifier); background: rgba(45,140,93,0.04); }
+.store-row-label { font-size: 12px; font-weight: 500; color: var(--fg); margin-bottom: 3px; }
+.store-row-meta { font-size: 10.5px; font-family: 'JetBrains Mono', monospace; color: var(--fg-dim); line-height: 1.5; }
+
+@media (max-width: 720px) {
+  .modal { width: 100% !important; max-height: 90vh; }
+}
+
+/* Section header in sidebar/inline */
+.sec-h {
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 10px;
+  letter-spacing: 0.18em;
+  text-transform: uppercase;
+  color: var(--fg-faint);
+  padding: 14px 14px 8px;
+  border-bottom: 1px solid var(--rule);
+  display: flex;
+  justify-content: space-between;
+  align-items: center;
+}
+
+/* Marquee strip — tiny live indicator */
+.live-strip {
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 10px;
+  letter-spacing: 0.06em;
+  color: var(--fg-faint);
+}
+
+/* Result cell — score bar */
+.score-bar {
+  display: inline-block;
+  height: 6px;
+  background: var(--verifier-bright);
+  margin-right: 6px;
+  vertical-align: middle;
+}
+
+/* Pulse */
+@keyframes pulse {
+  0%, 100% { opacity: 1; }
+  50% { opacity: 0.35; }
+}
+.pulse { animation: pulse 1.6s ease-in-out infinite; }
+
+/* No-red rule visual: refused is amber stripe */
+.honest-refusal-stripe {
+  background:
+    repeating-linear-gradient(45deg,
+      transparent 0 6px,
+      rgba(200,123,44,0.08) 6px 12px);
+}
+
+/* Segment glyph (collection / backend marker) */
+.glyph-square { width: 6px; height: 6px; background: currentColor; display: inline-block; }
+.glyph-ring { width: 6px; height: 6px; border: 1px solid currentColor; border-radius: 50%; display: inline-block; }
+.glyph-fill { width: 6px; height: 6px; background: currentColor; border-radius: 50%; display: inline-block; }
